### 3.2 修改 experience.html（经验记录页面）
**文件位置**：`extensions/public/experience.html`

#### 修改标签页
```html
<!-- 二级标签导航 -->
<div class="level2-tabs">
  <button class="level2-tab active" data-tab="columns">专栏</button>
  <button class="level2-tab" data-tab="experiences">经验</button>
  <button class="level2-tab" data-tab="notes">笔记</button>
  <!-- 新增标签 -->
  <button class="level2-tab" data-tab="your-tab">你的标签</button>
</div>
```

#### 添加新内容区域
```javascript
// 在 renderLevel2Content 函数中添加新 case
async function renderLevel2Content(tab) {
  switch (tab) {
    case 'columns':
      await renderColumns();
      break;
    case 'experiences':
      await renderExperiences();
      break;
    case 'notes':
      await renderNotes();
      break;
    // 新增你的 case
    case 'your-tab':
      await renderYourTab();
      break;
  }
}

async function renderYourTab() {
  const content = document.getElementById('level2-content');
  content.innerHTML = `
    <div class="your-tab-content">
      <h2>你的标签内容</h2>
    </div>
  `;
}
```

