    console.log('[YourFeature] 处理完成');
  } catch (error) {
    console.error('[YourFeature] 处理失败:', error);
    alert('处理失败: ' + error.message);
  }
});

// 表单提交事件
document.getElementById('your-form').addEventListener('submit', async (e) => {
  e.preventDefault();
  // 处理表单
});
```

### 6.3 DOM 操作
```javascript
// 创建元素
const div = document.createElement('div');
div.className = 'your-class';
div.innerHTML = '<p>你的内容</p>';

// 添加到页面
