```javascript
function getOrCreatePlanForWork(workId, fanqieLatest) {
  const today = new Date().toDateString();

  // 如果今天还没有计划，或者是新的一天，生成计划
  if (!plannedChapters[workId] || lastPlanDate !== today) {
    const plan = [];
    for (let i = 0; i < dailyChaptersPerWork; i++) {
      plan.push(fanqieLatest + i + 1);
