### 4.2 文件路径查找策略
当需要读取数据文件时，使用多种候选路径：
```typescript
function findDataPath(): string {
  const candidates = [
    // 从源码目录计算
    path.join(__dirname, 'data', 'columns.json'),
    // 从编译后目录计算
    path.join(__dirname, '..', 'data', 'columns.json'),
    // 绝对路径保底
    '/workspace/projects/extensions/plugins/experience-manager/data/columns.json',
  ];

  for (const candidate of candidates) {
    if (fs.existsSync(candidate)) {
      console.log('[Data] 找到文件:', candidate);
      return candidate;
    }
  }

  console.error('[Data] 未找到文件，尝试的路径:', candidates);
  return candidates[0];
}
```

